    const { data: stats, error: dbError } = await supabase
      .from('device_stats')
      .select('fcm_token')
      .eq('device_id', record.device_id)
      .not('fcm_token', 'is', null)
      .order('created_at', { ascending: false })
      .limit(1)

    if (dbError || !stats || stats.length === 0) {
